import com.google.common.collect.ImmutableSet;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Getter;
import lombok.NonNull;
import lombok.Setter;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

@Slf4j
@Builder
@AllArgsConstructor
public class BasisRszVerdelerDmfappl implements BasisRszVerdeler {
    public static final int AKE_CODE_101 = 101;

    private static final Set<CodeExtensie> AKE_MET_BASIS_WVL_VASTBENOEMD =
            ImmutableSet.of(CodeExtensie.VOORDEEL_VAN_ALLE_AARD_804_36, CodeExtensie.VOORDEEL_VAN_ALLE_AARD_804_38, CodeExtensie.VOORDEEL_VAN_ALLE_AARD_806_36,
                    CodeExtensie.VOORDEEL_VAN_ALLE_AARD_806_38);

    protected static final Set<CodeExtensie> AKE_MET_BASIS_PENSIOEN_MANDATARIS =
            ImmutableSet.of(CodeExtensie.TERUGBETALING_KOST_EIGEN_WG_441_106, CodeExtensie.TERUGBETALING_KOST_EIGEN_WG_441_107,
                    CodeExtensie.UITTREDING_PROV_GEDEPUTEERDE);

    @NonNull
    @Getter
    private final DmfapplBasisBijdrageService dmfapplBasisBijdrageService;
    @NonNull
    @Getter
    private final APKPrincipeService apkPrincipeService;
    @Getter
    private final RegulManager regulManager;
    @Getter
    @Setter
    protected LoonElement loonElement;
    @Getter
    @NonNull
    private final Hoedanigheid hoedanigheid;
    @Getter
    @NonNull
    private final Gsd typeGsd;
    @Getter
    protected final CategorieKengetalStatuutPensioenstelsel categorieKengetalStatuutPensioenstelsel;
    @Getter
    private final LocalDate gegevensDatum;
    @Getter
    private final BasisRszVerdelerOptions options;

    private static final List<Integer> CORONAPREMIE_LOONCODES = Collections.singletonList(1801);

    public void verdeelBasisRsz() {
        AardKodeExtensie loonCode = loonElement.getAardKodeExtensie();
        Money bedrag = loonElement.getPropertyMoney(RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY);
        if (bedrag.signum() != 0 && (heeftBasisRsz() || isLooncodeBasisPensioenBijdrageMandataris(loonCode))) {
            verdeelBasisRsz(loonCode, bedrag);
        } else {
            if (bedrag.signum() != 0 && LoonCodeTools.isBrugPensioen(loonCode)) {
                loonElement.putProperty(RekenBasisRszKey.BASIS_BRUG_PENSIOEN_KEY, bedrag);
            }
        }
        verdeelBasisRszBasisBijdragenSpecialeGevallen(loonCode, bedrag);
    }

    private void verdeelBasisRsz(AardKodeExtensie loonCode, Money bedrag) {
        verdeelBasisRszBasisBijdragen(loonCode, bedrag);
        verdeelBasisPensioenVastbenoemdenApk(loonCode, bedrag);
        verdeelBasisPensioenMandatarissenNietBeschermd(loonCode, bedrag);
        verdeelBasisPensioenMandatarisExtra(loonCode, bedrag);
        verdeelBasisWvl(loonCode, bedrag);
    }

    private void verdeelBasisRszBasisBijdragen(AardKodeExtensie loonCode, Money bedrag) {
        if (heeftBasisRsz()) {
            CategorieKengetal categorieKengetal = categorieKengetalStatuutPensioenstelsel.getCategorieKengetal();
            WerkgeversCategorie werkgeversCategorie = categorieKengetalStatuutPensioenstelsel.getWerkgeversCategorie();
            DmfapplWnkengetal werknemersKengetal = categorieKengetalStatuutPensioenstelsel.getDmfapplWnkengetal();
            DmfapplStatuutDmfappl statuutDmfappl = categorieKengetalStatuutPensioenstelsel.getStatuutDmfappl();
            boolean isStudent = categorieKengetal.isStudentMetBijzondereCategorie();
            if (isStudent) {
                werkgeversCategorie = getCategorieMapper().getContractuelenVakantieregelingPriveArbregOpenbaar();
                werknemersKengetal = getWerknemersKengetalMapper().getContractueleHandarbeiders();
            }

            Set<DmfapplWnkengetal> basisBijdragen = getDmfapplBasisBijdrages(loonCode, werkgeversCategorie, werknemersKengetal);
            for (DmfapplWnkengetal werknemersKengetalBijdrage : basisBijdragen) {
                Kengetal werknemersKengetal1 = getWerknemersKengetal(werknemersKengetalBijdrage);
                boolean werknemerskengetalBijdrageVoorStudent =
                        werknemersKengetal1.isWerknemerskengetalBijdrageVoorStudent(categorieKengetalStatuutPensioenstelsel.getStatuutDmfappl());
                if (!isStudent || werknemerskengetalBijdrageVoorStudent) {
                    verdeelBasisRszBasisBijdrage(werknemersKengetal, loonCode, bedrag, werknemersKengetalBijdrage, statuutDmfappl);
                }
            }
        }
    }

    public void verdeelBasisRszBasisBijdragenSpecialeGevallen(AardKodeExtensie loonCode, Money bedrag) {
        // Dmfappl heeft geen speciale gevallen
    }

    private Set<DmfapplWnkengetal> getDmfapplBasisBijdrages(AardKodeExtensie loonCode, WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal) {
        WerknemersKengetalLooncode werknemersKengetalLooncode = getWerknemersKengetalLooncode(loonCode, werknemersKengetal);
        Integer loonCodeCode = werknemersKengetalLooncode.getLooncodeCode();
        List<DmfapplBasisBijdrage> dmfapplBasisBijdragen = dmfapplBasisBijdrageService
                .findByWerkgeversCategorieWerknemersKengetalLooncode(werkgeversCategorie, werknemersKengetal, loonCodeCode, gegevensDatum);
        Set<DmfapplWnkengetal> basisBijdragen = dmfapplBasisBijdragen.stream()
                .map(DmfapplBasisBijdrage::getWerknemersKengetalBijdrage)
                .collect(Collectors.toSet());

        basisBijdragen.addAll(getDmfapplBasisBijdragesHardCoded(werknemersKengetalLooncode));

        if (basisBijdragen.isEmpty()) {
            String opmerking = "Geen basisbijdragen gevonden voor werkgeversCategorie " + werkgeversCategorie.getCode()
                    + ", werknemersKengetal " + werknemersKengetal.getCode() + ", loonCodeCode " + loonCodeCode + ", gegevensDatum " + gegevensDatum;
            log.debug(opmerking);
            regulManager.doRegulException(loonElement.getOpdracht(), Regulkode.RSZREGIME_NIET_GEVONDEN, opmerking);
        }
        return basisBijdragen;
    }

    protected List<DmfapplWnkengetal> getDmfapplBasisBijdragesHardCoded(WerknemersKengetalLooncode werknemersKengetalLooncode) {
        Integer loonCode = werknemersKengetalLooncode.getLooncodeCode();
        List<DmfapplWnkengetal> extraBasisBijdragen = new ArrayList<>();
        if (CORONAPREMIE_LOONCODES.contains(loonCode)) {
            extraBasisBijdragen.add(DmfapplWnkengetal.CORONAPREMIE_KOOPKRACHTPREMIE);
        }
        return extraBasisBijdragen;
    }

    protected void verdeelBasisRszBasisBijdrage(
            DmfapplWnkengetal werknemersKengetal, AardKodeExtensie loonCode, Money bedrag, DmfapplWnkengetal werknemersKengetalBijdrage,
            DmfapplStatuutDmfappl statuutDmfappl) {
        if (werknemersKengetal != werknemersKengetalBijdrage) {
            verdeelBasisRszNaarWerknemersKengetalBijdrage(werknemersKengetal, werknemersKengetalBijdrage, statuutDmfappl, bedrag);
        } else if (hoedanigheid == Hoedanigheid.MANDATARISSEN) {
            log.debug("Skip, LPBUNI-29033 mandatarissen mogen geen 400 hebben");
        } else {
            loonElement.putProperty(RekenBasisRszKey.BASIS_RSZ_KEY, bedrag);
            setBasisVerminderingPatronale(loonCode, bedrag);
        }
    }

    protected void setBasisVerminderingPatronale(AardKodeExtensie loonCode, Money bedrag) {
        if (!loonCode.behoortTotGroep(LooncodeGroepKeyStrings.GEEN_VERM_PATRONALE_BIJDRAGE_KEY) && options.isHeeftVerminderingPatronaleRsz()) {
            loonElement.putProperty(RekenBasisRszKey.BASIS_VERMINDERING_PATRONALE_KEY, bedrag);
        }
    }

    protected void verdeelBasisRszNaarWerknemersKengetalBijdrage(
            DmfapplWnkengetal werknemersKengetal, DmfapplWnkengetal werknemersKengetalBijdrage,
            DmfapplStatuutDmfappl statuutDmfappl, Money bedrag) {
        switch (werknemersKengetalBijdrage) {
            case BIJZONDERE_BIJDRAGE_BUITENWETTELIJK_PENSIOEN:
            case NGNATPERS_BIJZBIJDR_BW_PENS_R_EXWN:
            case BIJZBIJDR_BW_PENS_ONDERNPLAN:
                loonElement.putProperty(RekenBasisRszKey.BASIS_BUITENWETTELIJK_PENSIOEN_KEY, bedrag);
                break;
            case BIJDRAGE_DUBBEL_VAKANTIEGELD:
                loonElement.putProperty(RekenBasisRszKey.BASIS_DUBBEL_VAKANTIEGELD_KEY, bedrag);
                break;
            case BIJDRAGE_DUBBEL_VAKANTIEGELD_MANDATARIS:
                loonElement.putProperty(RekenBasisRszKey.BASIS_DUBBEL_VAKANTIEGELD_MANDATARIS_KEY, bedrag);
                break;
            case BIJDRAGE_VERKEERSBOETE:
                loonElement.putProperty(RekenBasisRszKey.BASIS_TERUGBETALING_VERKEERSBOETES_KEY, bedrag);
                break;
            case PENSIOENBIJDRAGE_VASTBENOEMD_GEMEENSCHAPPELIJK_STELSEL:
            case PENSIOENBIJDRAGE_VASTBENOEMD_NIEUW_AANGESLOTEN:
            case PENSIOENBIJDRAGE_VASTBENOEMD_GEINTEGREERD_LOKALE_POLITIE:
            case BASISPENSBIJDR_EX_GEMEENSCH:
            case BASISPENSBIJDR_EX_NIEUW_RIJKSDIENST_HOOG_PERC:
            case BASISPENSBIJDR_LOKALE_POLITIE:
            case BASISPENSBIJDR_AANGSL_NA2011_LAAG_PERC:
            case BASISPENSBIJDR_EX_VOORZORGINST_SPECIFIEK_BIJDRVOET:
            case BASISPENSBIJDR_PARASTATALEN:
                loonElement.putProperty(RekenBasisRszKey.BASIS_PENSIOENBIJDRAGE_KEY, bedrag);
                break;
            case BIJDRAGE_AANVUL_PENS_CONTR:
                verdeelBasisBonusPensioenpijler2(bedrag);
                break;
            case BIJDRAGE_OP_TAO:
                loonElement.putProperty(RekenBasisRszKey.BASIS_TAO_KEY, bedrag);
                break;
            case VOLLEDIGE_VRIJSTELLING:
                loonElement.putProperty(RekenBasisRszKey.BASIS_NIET_ONDERWORPEN_KEY, bedrag);
                break;
            case WERKLOOSHEIDSBIJDRAGE_1_69:
            case C846:
            case TERUGBETALING_GEWONE_SOCIALEZEKERHEID_BIJDRAGE_SYNDICAAL_GED:
            case TERUGBETALING_PENSIOENBIJDRAGE_VASTBENOEMD_SYNDICAAL_GEDETAC:
            case TERUGBETALING_PENSIOENBIJDRAGE_1_69_SYNDICAAL_GEDETACHEERD:
            case CODE_843:
            case CODE_878:
                //doe niets
                break;
            case BIJDRAGE_GSD:
                verdeelBasisRszBijdrageGsd(bedrag);
                break;
            case BIJDRAGE_GSD_VLAANDEREN:
                verdeelBasisRszBijdrageGsdVlaanderen(werknemersKengetal, bedrag);
                break;
            case BIJZONDERE_BIJDRAGE_MOBILITEITSBUDGET_3E_PIJLER:
                loonElement.putProperty(RekenBasisRszKey.BASIS_MOBILITEITSBUDGET_KEY, bedrag);
                break;
            case CORONAPREMIE_KOOPKRACHTPREMIE:
                loonElement.putProperty(RekenBasisRszKey.BASIS_CORONAPREMIE_KEY, bedrag);
                break;
            default:
                regulManager.doRegulException(loonElement.getOpdracht(), Regulkode.RSZREGIME_NIET_GEPROGRAMMEERD);
                break;
        }
    }

    public void verdeelBasisBonusPensioenpijler2(Money bedrag) {
        if (options.isBerekenTweedePensioenPijler()) {
            loonElement.putProperty(RekenBasisRszKey.BASIS_TWEEDE_PENSIOENPIJLER_KEY, bedrag);
            if (options.isBonusTweedePensioenPijler()) {
                loonElement.putProperty(RekenBasisRszKey.BASIS_BONUS_TWEEDE_PENSIOENPIJLER_KEY, bedrag);
            }
        }
    }

    protected void verdeelBasisRszBijdrageGsd(Money bedrag) {
        if (typeGsd == Gsd.GSD) {
            loonElement.putProperty(RekenBasisRszKey.BASIS_GSD_KEY, bedrag);
        }
    }

    protected void verdeelBasisRszBijdrageGsdVlaanderen(DmfapplWnkengetal werknemersKengetalBijdrage, Money bedrag) {
        Kengetal werknemersKengetal = getWerknemersKengetal(werknemersKengetalBijdrage);
        boolean isTeVerdelenGsdMin = typeGsd == Gsd.V_MIN && werknemersKengetal.isGeenLokaleMandataris();
        if (typeGsd == Gsd.V_PLUS || isTeVerdelenGsdMin) {
            loonElement.putProperty(RekenBasisRszKey.BASIS_GSD_KEY, bedrag);
        }
    }

    protected void verdeelBasisPensioenVastbenoemdenApk(AardKodeExtensie loonCode, Money bedrag) {
        CategorieKengetal categorieKengetal = categorieKengetalStatuutPensioenstelsel.getCategorieKengetal();
        WerkgeversCategorie werkgeversCategorie = categorieKengetal.getWerkgeversCategorie();
        DmfapplWnkengetal werknemersKengetal = categorieKengetal.getDmfapplWnkengetal();
        APKPrincipe apkPrincipe =
                apkPrincipeService.getByWerkgeversCategorieWerknemersKengetalLooncodeDatum(werkgeversCategorie, werknemersKengetal, loonCode.getCode(), gegevensDatum);
        if (apkPrincipe != null) {
            loonElement.putProperty(RekenBasisRszKey.BASIS_PENSIOEN_VASTBENOEMDEN_APK_KEY, bedrag);
        }
    }

    protected void verdeelBasisPensioenMandatarissenNietBeschermd(AardKodeExtensie loonCode, Money bedrag) {
        if (loonCode.getCode() == AKE_CODE_101 && hoedanigheid == Hoedanigheid.MANDATARISSEN_NIET_BESCHERMD) {
            loonElement.putProperty(RekenBasisRszKey.BASIS_PENSIOEN_MANDATARIS_KEY, bedrag);
        }
    }

    private void verdeelBasisPensioenMandatarisExtra(AardKodeExtensie loonCode, Money bedrag) {
        if (isLooncodeBasisPensioenBijdrageMandataris(loonCode)) {
            loonElement.putProperty(RekenBasisRszKey.BASIS_PENSIOEN_MANDATARIS_KEY, bedrag);
        }
    }

    private boolean isLooncodeBasisPensioenBijdrageMandataris(AardKodeExtensie loonCode) {
        return LoonCodeTools.matches(loonCode.getCode(), loonCode.getExtensie(), AKE_MET_BASIS_PENSIOEN_MANDATARIS) &&
                (hoedanigheid == Hoedanigheid.MANDATARISSEN || hoedanigheid == Hoedanigheid.MANDATARISSEN_NIET_BESCHERMD);
    }

    private void verdeelBasisWvl(AardKodeExtensie loonCode, Money bedrag) {
        if (isLooncodeBasisWvl(loonCode)) {
            loonElement.putProperty(RekenBasisRszKey.BASIS_WVL_KEY, bedrag);
        }
    }

    private boolean isLooncodeBasisWvl(AardKodeExtensie loonCode) {
        return LoonCodeTools.matches(loonCode.getCode(), loonCode.getExtensie(), AKE_MET_BASIS_WVL_VASTBENOEMD) &&
                hoedanigheid == Hoedanigheid.VASTBENOEMDEN;
    }


    protected Kengetal getWerknemersKengetal(DmfapplWnkengetal kengetal) {
        return new KengetalDmfappl(kengetal);
    }

    protected CategorieKengetal getCategorieKengetal(WerkgeversCategorie categorie, DmfapplWnkengetal kengetal) {
        return new CategorieKengetalDmfappl(categorie, kengetal);
    }

    protected KengetalMapper getWerknemersKengetalMapper() {
        return new KengetalMapperDmfappl();
    }

    protected CategorieMapper getCategorieMapper() {
        return new CategorieMapperDmfappl();
    }

    public WerknemersKengetalLooncode getWerknemersKengetalLooncode(AardKodeExtensie loonCode, DmfapplWnkengetal werknemersKengetal) {
        return new WerknemersKengetalLooncodeDmfappl(loonCode, werknemersKengetal);
    }

    protected boolean heeftBasisRsz() {
        return RszTools.heeftBasisRsz(loonElement.getAardKodeExtensie());
    }
}
